// src/middleware/session-auth.ts
init_supabase();
async function requirePortalSession(c2, next) {
  const authHeader = c2.req.header("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return c2.json({ error: "Missing or invalid Authorization header" }, 401);
  }
  const jwt = authHeader.slice(7).trim();
  if (!jwt) {
    return c2.json({ error: "Empty token" }, 401);
  }
  try {
    const { data: { user }, error: authError } = await supabase.auth.getUser(jwt);
    if (authError || !user) {
      return c2.json({ error: "Invalid or expired session" }, 401);
    }
    const userId = user.id;
    const email = user.email ?? "";
    const { data: platformAdmin } = await supabase.from("platform_admins").select("id").eq("user_id", userId).maybeSingle();
    const isSuperAdmin = !!platformAdmin;
    const { data: membership } = await supabase.from("tenant_users").select("id, role, tenant:tenants(id, name, slug)").eq("user_id", userId).maybeSingle();
    const membershipData = membership;
    c2.set("portalSession", {
      user_id: userId,
      email,
      tenant_id: membershipData?.tenant?.id ?? null,
      tenant_slug: membershipData?.tenant?.slug ?? null,
      tenant_name: membershipData?.tenant?.name ?? null,
      role: membershipData?.role ?? null,
      membership_id: membershipData?.id ?? null,
      is_super_admin: isSuperAdmin
    });
    await next();
  } catch (err) {
    const err_ = err;
    const status = err_.statusCode ?? 401;
    return c2.json({
      error: err_.message ?? "Invalid session",
      code: err_.code ?? "SESSION_INVALID"
    }, status);
  }
}
function requirePortalRole(...roles) {
  return async (c2, next) => {
    const session = c2.get("portalSession");
    if (!session) {
      return c2.json({ error: "Portal session required" }, 401);
    }
    if (!session.role || !roles.includes(session.role)) {
      return c2.json({
        error: `This endpoint requires one of these roles: ${roles.join(", ")}`
      }, 403);
    }
    await next();
  };
}
function getSession(c2) {
  return c2.get("portalSession");
}
function requireSuperAdmin() {
  return async (c2, next) => {
    const session = c2.get("portalSession");
    if (!session) {
      return c2.json({ error: "Portal session required" }, 401);
    }
    if (!session.is_super_admin) {
      return c2.json({ error: "Super admin access required" }, 403);
    }
    await next();
  };
}

// src/lib/plan-store.ts
init_supabase();
var planCache = /* @__PURE__ */ new Map();
var CACHE_TTL_MS = 5 * 60 * 1e3;
async function fetchPlanForTenant(tenantId) {
  const { data: tenant } = await supabase.from("tenants").select("plan_id").eq("id", tenantId).maybeSingle();
  if (!tenant?.plan_id) return null;
  const { data: plan } = await supabase.from("plans").select("*").eq("id", tenant.plan_id).single();
  if (!plan) return null;
  const features = plan.features ?? {};
  const _raw_features = { ...features };
  const extractedFeatures = {};
  for (const [key, value] of Object.entries(features)) {
    if (typeof value === "boolean" || typeof value === "number" || typeof value === "string" || value === null) {
      extractedFeatures[key] = value;
    }
  }
  return {
    id: plan.id,
    name: plan.name,
    price_monthly: plan.price_monthly,
    max_users: plan.max_users,
    max_tenants: plan.max_tenants,
    max_api_keys: plan.max_api_keys,
    api_calls_per_day: plan.api_calls_per_day,
    audit_retention_days: plan.audit_retention_days,
    features: extractedFeatures,
    _raw_features
  };
}
async function getPlanForTenant(tenantId) {
  const cached2 = planCache.get(tenantId);
  if (cached2 && Date.now() - cached2.fetchedAt < CACHE_TTL_MS) {
    return cached2.plan;
  }
  const plan = await fetchPlanForTenant(tenantId);
  if (plan) {
    planCache.set(tenantId, { plan, fetchedAt: Date.now() });
  }
  return plan;
}
async function hasPlanFeature(tenantId, feature) {
  const plan = await getPlanForTenant(tenantId);
  if (!plan) return false;
  return plan.features[feature] === true;
}
function invalidatePlanCache(tenantId) {
  planCache.delete(tenantId);
}

